import jwt
import datetime

# SECRET_KEY is used for encoding and decoding JWT
SECRET_KEY = "YOUR_SECRET_KEY"

def generate_token(user_id, role):
    # Defining when the token will expire
    expiration_time = datetime.datetime.utcnow() + datetime.timedelta(minutes=60)  # expires in 60 min

    jwt_payload = {
        "user_id": user_id,
        "user_role": role,
        "exp": expiration_time
    }

    # Generating JWT
    token = jwt.encode(jwt_payload, SECRET_KEY, algorithm='HS256')

    return token.decode('UTF-8')